import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import axios from 'axios';

function Post() {
    const { id } = useParams();
    const [postObject, setPostObject] = useState({});
    const [comments, setComments] = useState([]);
    const [newComment, setNewComment] = useState("");

    useEffect(() => {
        axios.get(`http://localhost:3001/posts/byId/${id}`).then((response) => {
            setPostObject(response.data);
            // console.log(response.data);
        });

        axios.get(`http://localhost:3001/comments/${id}`).then((response) => {
            setComments(response.data);
        });
    }, []);

    const addComment = () => {
        axios
        .post('http://localhost:3001/comments', {
            commentBody: newComment, 
            PostId: id,
        }, {
           headers : {
            accessToken: sessionStorage.getItem("accessToken"), //better to do through cookies
           } 
        })
        .then((response) => {
            // to update comments, show on page without reload
            let commentToAdd = {commentBody: newComment};
            setComments([...comments, commentToAdd]);
            setNewComment(""); //set comment to "" and delete it from value in input
        });
    }
  return (
    <div className='postPage'>
        <div className='leftSide'>
            <div className='post'>
                <div className='title'>{postObject.title}</div>
                <div className='body'>{postObject.postText}</div>
                <div className='footer'>{postObject.username}</div>
            </div>
        </div>
        <div className='rightSide'>
            <div className='addCommentContainer'>
                <input 
                    type='text' 
                    placeholder='Comment...' 
                    autoComplete='disabled' 
                    value={newComment}
                    onChange={(event) => {setNewComment(event.target.value)}}
                />
                <button onClick={addComment}>Add Comment</button>
            </div>
            <div className='listOfComments'>
                {comments.map((comment, key) => {
                    return <div key={key} className='comment'>{comment.commentBody}</div>
                })}
            </div>
        </div>
    </div>
  )
}

export default Post
